import{_ as a,o as s,c as n,a4 as e}from"./chunks/framework._in6GHBg.js";const c=JSON.parse('{"title":"稳态与调节详解","description":"","frontmatter":{},"headers":[],"relativePath":"biology/regulation.md","filePath":"biology/regulation.md"}'),l={name:"biology/regulation.md"};function i(r,t,p,o,d,g){return s(),n("div",null,[...t[0]||(t[0]=[e(`<h1 id="稳态与调节详解" tabindex="-1">稳态与调节详解 <a class="header-anchor" href="#稳态与调节详解" aria-label="Permalink to &quot;稳态与调节详解&quot;">​</a></h1><p><strong>生命的自我维持——从分子到整体的精密调控</strong></p><hr><h2 id="一、本章地图" tabindex="-1">一、本章地图 <a class="header-anchor" href="#一、本章地图" aria-label="Permalink to &quot;一、本章地图&quot;">​</a></h2><h3 id="核心目标" tabindex="-1">核心目标 <a class="header-anchor" href="#核心目标" aria-label="Permalink to &quot;核心目标&quot;">​</a></h3><p>学完本章，你将：</p><ol><li>理解神经调节的基本机制</li><li>掌握体液调节（激素调节）的主要过程</li><li>理解免疫系统的防卫功能</li><li>了解植物激素调节</li></ol><h3 id="知识网络" tabindex="-1">知识网络 <a class="header-anchor" href="#知识网络" aria-label="Permalink to &quot;知识网络&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>稳态与调节</span></span>
<span class="line"><span>├── 动物生命活动的调节</span></span>
<span class="line"><span>│   ├── 神经调节 ⭐</span></span>
<span class="line"><span>│   ├── 体液调节 ⭐</span></span>
<span class="line"><span>│   ├── 血糖调节 ⭐</span></span>
<span class="line"><span>│   └── 体温调节和水盐调节</span></span>
<span class="line"><span>├── 免疫调节 ⭐</span></span>
<span class="line"><span>│   ├── 免疫系统的组成</span></span>
<span class="line"><span>│   ├── 体液免疫</span></span>
<span class="line"><span>│   └── 细胞免疫</span></span>
<span class="line"><span>└── 植物生命活动的调节</span></span>
<span class="line"><span>    ├── 生长素的发现</span></span>
<span class="line"><span>    ├── 生长素的生理作用</span></span>
<span class="line"><span>    └── 其他植物激素</span></span></code></pre></div><hr><h2 id="二、概念定义" tabindex="-1">二、概念定义 <a class="header-anchor" href="#二、概念定义" aria-label="Permalink to &quot;二、概念定义&quot;">​</a></h2><h3 id="_2-1-神经调节-⭐" tabindex="-1">2.1 神经调节 ⭐ <a class="header-anchor" href="#_2-1-神经调节-⭐" aria-label="Permalink to &quot;2.1 神经调节 ⭐&quot;">​</a></h3><h4 id="_2-1-1-神经调节的结构基础" tabindex="-1">2.1.1 神经调节的结构基础 <a class="header-anchor" href="#_2-1-1-神经调节的结构基础" aria-label="Permalink to &quot;2.1.1 神经调节的结构基础&quot;">​</a></h4><p><strong>神经元</strong>：神经系统的基本结构和功能单位</p><p><strong>神经元结构</strong>：</p><ul><li><strong>细胞体</strong>：含细胞核，代谢中心</li><li><strong>树突</strong>：短而多，接受信息</li><li><strong>轴突</strong>：长而少，传导信息</li></ul><p><strong>反射弧</strong>（完成反射的结构基础）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>感受器 → 传入神经 → 神经中枢 → 传出神经 → 效应器</span></span></code></pre></div><p><strong>注意</strong>：反射必须经过完整的反射弧</p><h4 id="_2-1-2-兴奋在神经纤维上的传导" tabindex="-1">2.1.2 兴奋在神经纤维上的传导 <a class="header-anchor" href="#_2-1-2-兴奋在神经纤维上的传导" aria-label="Permalink to &quot;2.1.2 兴奋在神经纤维上的传导&quot;">​</a></h4><p><strong>静息电位</strong>：</p><ul><li>状态：未受刺激时</li><li>电位：外正内负（K⁺外流）</li></ul><p><strong>动作电位</strong>：</p><ul><li>状态：受刺激时</li><li>电位：外负内正（Na⁺内流）</li></ul><p><strong>传导特点</strong>：</p><ul><li><strong>双向传导</strong>（在离体神经纤维上）</li><li><strong>电信号</strong>（局部电流）</li><li><strong>不衰减</strong></li></ul><p><strong>传导过程</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>刺激 → 膜电位变化（外正内负→外负内正）→ 局部电流 → 邻近部位兴奋 → 兴奋向前传导</span></span></code></pre></div><h4 id="_2-1-3-兴奋在神经元之间的传递" tabindex="-1">2.1.3 兴奋在神经元之间的传递 <a class="header-anchor" href="#_2-1-3-兴奋在神经元之间的传递" aria-label="Permalink to &quot;2.1.3 兴奋在神经元之间的传递&quot;">​</a></h4><p><strong>结构基础</strong>：突触</p><p><strong>突触结构</strong>：</p><ul><li><strong>突触前膜</strong>：上一个神经元的轴突末梢膜</li><li><strong>突触间隙</strong>：两膜之间的组织液</li><li><strong>突触后膜</strong>：下一个神经元的树突或细胞体膜</li></ul><p><strong>传递过程</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>电信号（突触前膜）→ 释放神经递质 → 化学信号（突触间隙）→ 与受体结合 → 电信号（突触后膜）</span></span></code></pre></div><p><strong>传递特点</strong>：</p><ul><li><strong>单向传递</strong>（只能从突触前膜到突触后膜）</li><li><strong>信号转换</strong>：电信号→化学信号→电信号</li><li><strong>时间延搁</strong></li></ul><p><strong>神经递质</strong>：</p><ul><li>种类：乙酰胆碱、多巴胺等</li><li>作用：使下一个神经元兴奋或抑制</li><li>灭活：作用后被酶分解或回收</li></ul><hr><h3 id="_2-2-体液调节-⭐" tabindex="-1">2.2 体液调节 ⭐ <a class="header-anchor" href="#_2-2-体液调节-⭐" aria-label="Permalink to &quot;2.2 体液调节 ⭐&quot;">​</a></h3><p><strong>概念</strong>：激素等化学物质通过体液传送的方式对生命活动进行调节</p><p><strong>激素调节的特点</strong>：</p><ul><li><strong>微量和高效</strong></li><li><strong>通过体液运输</strong></li><li><strong>作用于靶器官、靶细胞</strong></li><li><strong>作为信使传递信息</strong></li></ul><p><strong>主要内分泌腺及其激素</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">内分泌腺</th><th style="text-align:center;">激素</th><th style="text-align:left;">主要作用</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>下丘脑</strong></td><td style="text-align:center;">促激素释放激素</td><td style="text-align:left;">调节垂体的分泌活动</td></tr><tr><td style="text-align:center;"></td><td style="text-align:center;">抗利尿激素</td><td style="text-align:left;">促进肾小管和集合管对水的重吸收</td></tr><tr><td style="text-align:center;"><strong>垂体</strong></td><td style="text-align:center;">生长激素</td><td style="text-align:left;">促进生长</td></tr><tr><td style="text-align:center;"></td><td style="text-align:center;">促甲状腺激素</td><td style="text-align:left;">促进甲状腺的生长发育和分泌</td></tr><tr><td style="text-align:center;"><strong>甲状腺</strong></td><td style="text-align:center;">甲状腺激素</td><td style="text-align:left;">促进新陈代谢和生长发育，提高神经系统的兴奋性</td></tr><tr><td style="text-align:center;"><strong>胰岛</strong></td><td style="text-align:center;">胰岛素</td><td style="text-align:left;">降低血糖</td></tr><tr><td style="text-align:center;"></td><td style="text-align:center;">胰高血糖素</td><td style="text-align:left;">升高血糖</td></tr><tr><td style="text-align:center;"><strong>肾上腺</strong></td><td style="text-align:center;">肾上腺素</td><td style="text-align:left;">升高血糖，加快心跳</td></tr></tbody></table><hr><h3 id="_2-3-血糖调节-⭐" tabindex="-1">2.3 血糖调节 ⭐ <a class="header-anchor" href="#_2-3-血糖调节-⭐" aria-label="Permalink to &quot;2.3 血糖调节 ⭐&quot;">​</a></h3><p><strong>血糖平衡</strong>：血糖浓度维持在0.8-1.2g/L（或80-120mg/dL）</p><p><strong>调节机制</strong>：</p><p><strong>血糖升高时</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>血糖升高 → 胰岛B细胞 → 胰岛素分泌增加</span></span>
<span class="line"><span>                ↓</span></span>
<span class="line"><span>        促进组织细胞摄取、利用和储存葡萄糖</span></span>
<span class="line"><span>                ↓</span></span>
<span class="line"><span>            血糖降低</span></span></code></pre></div><p><strong>血糖降低时</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>血糖降低 → 胰岛A细胞 → 胰高血糖素分泌增加</span></span>
<span class="line"><span>                ↓</span></span>
<span class="line"><span>        促进肝糖原分解和非糖物质转化为葡萄糖</span></span>
<span class="line"><span>                ↓</span></span>
<span class="line"><span>            血糖升高</span></span></code></pre></div><p><strong>特点</strong>：</p><ul><li><strong>拮抗作用</strong>：胰岛素和胰高血糖素作用相反</li><li><strong>反馈调节</strong>：血糖变化→激素分泌→血糖恢复正常</li></ul><hr><h3 id="_2-4-甲状腺激素的分级调节" tabindex="-1">2.4 甲状腺激素的分级调节 <a class="header-anchor" href="#_2-4-甲状腺激素的分级调节" aria-label="Permalink to &quot;2.4 甲状腺激素的分级调节&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>寒冷/紧张 → 下丘脑 → 促甲状腺激素释放激素(TRH)</span></span>
<span class="line"><span>                ↓</span></span>
<span class="line"><span>            垂体 → 促甲状腺激素(TSH)</span></span>
<span class="line"><span>                ↓</span></span>
<span class="line"><span>            甲状腺 → 甲状腺激素</span></span>
<span class="line"><span>                ↓</span></span>
<span class="line"><span>        促进新陈代谢，增加产热</span></span></code></pre></div><p><strong>反馈调节</strong>：</p><ul><li>甲状腺激素过多→抑制下丘脑和垂体→TRH和TSH减少→甲状腺激素分泌减少</li><li>维持甲状腺激素含量的相对稳定</li></ul><hr><h3 id="_2-5-免疫调节-⭐" tabindex="-1">2.5 免疫调节 ⭐ <a class="header-anchor" href="#_2-5-免疫调节-⭐" aria-label="Permalink to &quot;2.5 免疫调节 ⭐&quot;">​</a></h3><h4 id="_2-5-1-免疫系统的组成" tabindex="-1">2.5.1 免疫系统的组成 <a class="header-anchor" href="#_2-5-1-免疫系统的组成" aria-label="Permalink to &quot;2.5.1 免疫系统的组成&quot;">​</a></h4><ul><li><strong>免疫器官</strong>：胸腺、骨髓、脾、淋巴结、扁桃体</li><li><strong>免疫细胞</strong>：淋巴细胞（T细胞、B细胞）、吞噬细胞</li><li><strong>免疫活性物质</strong>：抗体、淋巴因子、溶菌酶</li></ul><h4 id="_2-5-2-免疫系统的功能" tabindex="-1">2.5.2 免疫系统的功能 <a class="header-anchor" href="#_2-5-2-免疫系统的功能" aria-label="Permalink to &quot;2.5.2 免疫系统的功能&quot;">​</a></h4><ol><li><strong>防卫功能</strong>：抵御病原体的攻击</li><li><strong>监控功能</strong>：监控体内衰老、损伤细胞</li><li><strong>清除功能</strong>：清除衰老、损伤、癌变细胞</li></ol><h4 id="_2-5-3-三道防线" tabindex="-1">2.5.3 三道防线 <a class="header-anchor" href="#_2-5-3-三道防线" aria-label="Permalink to &quot;2.5.3 三道防线&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:center;">防线</th><th style="text-align:center;">组成</th><th style="text-align:center;">特点</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>第一道</strong></td><td style="text-align:center;">皮肤、黏膜</td><td style="text-align:center;">非特异性</td></tr><tr><td style="text-align:center;"><strong>第二道</strong></td><td style="text-align:center;">体液中的杀菌物质和吞噬细胞</td><td style="text-align:center;">非特异性</td></tr><tr><td style="text-align:center;"><strong>第三道</strong></td><td style="text-align:center;">免疫器官和免疫细胞</td><td style="text-align:center;">特异性</td></tr></tbody></table><h4 id="_2-5-4-特异性免疫" tabindex="-1">2.5.4 特异性免疫 <a class="header-anchor" href="#_2-5-4-特异性免疫" aria-label="Permalink to &quot;2.5.4 特异性免疫&quot;">​</a></h4><p><strong>体液免疫</strong>（针对细胞外病原体）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>抗原 → 吞噬细胞处理 → T细胞 → B细胞</span></span>
<span class="line"><span>                            ↓</span></span>
<span class="line"><span>                    增殖分化 → 浆细胞 + 记忆细胞</span></span>
<span class="line"><span>                            ↓</span></span>
<span class="line"><span>                        分泌抗体 → 与抗原结合 → 清除抗原</span></span></code></pre></div><p><strong>细胞免疫</strong>（针对细胞内病原体，如病毒感染的细胞）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>抗原 → 吞噬细胞处理 → T细胞</span></span>
<span class="line"><span>                    ↓</span></span>
<span class="line"><span>            增殖分化 → 效应T细胞 + 记忆细胞</span></span>
<span class="line"><span>                    ↓</span></span>
<span class="line"><span>            与靶细胞密切接触 → 靶细胞裂解死亡</span></span></code></pre></div><p><strong>记忆细胞</strong>：</p><ul><li>作用：记住特定抗原，下次遇到同种抗原时快速反应</li><li>特点：寿命长，保持对抗原的记忆</li></ul><hr><h3 id="_2-6-植物激素调节" tabindex="-1">2.6 植物激素调节 <a class="header-anchor" href="#_2-6-植物激素调节" aria-label="Permalink to &quot;2.6 植物激素调节&quot;">​</a></h3><h4 id="_2-6-1-生长素" tabindex="-1">2.6.1 生长素 <a class="header-anchor" href="#_2-6-1-生长素" aria-label="Permalink to &quot;2.6.1 生长素&quot;">​</a></h4><p><strong>发现</strong>：达尔文、鲍森·詹森、拜尔、温特等科学家的实验</p><p><strong>合成部位</strong>：幼嫩的芽、叶和发育中的种子</p><p><strong>运输</strong>：</p><ul><li><strong>极性运输</strong>：从形态学上端向形态学下端运输</li><li><strong>横向运输</strong>：单侧光、重力等因素影响</li></ul><p><strong>生理作用</strong>：</p><ul><li><strong>两重性</strong>：低浓度促进生长，高浓度抑制生长</li><li><strong>表现</strong>： <ul><li>促进扦插枝条生根</li><li>促进果实发育</li><li>防止落花落果</li><li>高浓度可作为除草剂（抑制双子叶杂草）</li></ul></li></ul><p><strong>应用</strong>：</p><ul><li>顶端优势：摘除顶芽，促进侧芽生长</li><li>根的向地性、茎的背地性</li></ul><h4 id="_2-6-2-其他植物激素" tabindex="-1">2.6.2 其他植物激素 <a class="header-anchor" href="#_2-6-2-其他植物激素" aria-label="Permalink to &quot;2.6.2 其他植物激素&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:center;">激素</th><th style="text-align:center;">合成部位</th><th style="text-align:left;">主要作用</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>赤霉素</strong></td><td style="text-align:center;">未成熟种子、幼根、幼芽</td><td style="text-align:left;">促进细胞伸长，促进种子萌发和果实发育</td></tr><tr><td style="text-align:center;"><strong>细胞分裂素</strong></td><td style="text-align:center;">根尖</td><td style="text-align:left;">促进细胞分裂</td></tr><tr><td style="text-align:center;"><strong>脱落酸</strong></td><td style="text-align:center;">根冠、萎蔫叶片</td><td style="text-align:left;">抑制细胞分裂，促进叶和果实的衰老和脱落</td></tr><tr><td style="text-align:center;"><strong>乙烯</strong></td><td style="text-align:center;">植物体各部位</td><td style="text-align:left;">促进果实成熟</td></tr></tbody></table><hr><h2 id="三、典型例题" tabindex="-1">三、典型例题 <a class="header-anchor" href="#三、典型例题" aria-label="Permalink to &quot;三、典型例题&quot;">​</a></h2><h3 id="例题1-神经调节" tabindex="-1">例题1：神经调节 <a class="header-anchor" href="#例题1-神经调节" aria-label="Permalink to &quot;例题1：神经调节&quot;">​</a></h3><p><strong>题目</strong>：下图表示反射弧的结构，请回答：</p><ul><li>(1) 图中A、B、C、D、E分别表示什么？</li><li>(2) 兴奋在C处的传递为什么是单向的？</li></ul><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(1) A：感受器，B：传入神经，C：突触，D：传出神经，E：效应器</span></span>
<span class="line"><span></span></span>
<span class="line"><span>(2) 因为神经递质只能由突触前膜释放，作用于突触后膜，</span></span>
<span class="line"><span>    所以兴奋只能从突触前神经元传到突触后神经元，是单向的。</span></span></code></pre></div><hr><h3 id="例题2-血糖调节" tabindex="-1">例题2：血糖调节 <a class="header-anchor" href="#例题2-血糖调节" aria-label="Permalink to &quot;例题2：血糖调节&quot;">​</a></h3><p><strong>题目</strong>：某人在饭后血糖浓度变化如图所示（先升高后恢复正常），请解释：</p><ul><li>(1) 血糖升高的原因</li><li>(2) 血糖恢复正常的原因</li></ul><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(1) 饭后食物中的糖类被消化吸收，葡萄糖进入血液，使血糖升高。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>(2) 血糖升高刺激胰岛B细胞分泌胰岛素增加，胰岛素促进组织细胞</span></span>
<span class="line"><span>    加速摄取、利用和储存葡萄糖，使血糖降低并恢复正常水平。</span></span></code></pre></div><hr><h3 id="例题3-免疫调节" tabindex="-1">例题3：免疫调节 <a class="header-anchor" href="#例题3-免疫调节" aria-label="Permalink to &quot;例题3：免疫调节&quot;">​</a></h3><p><strong>题目</strong>：简述体液免疫的过程。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>大多数病原体经过吞噬细胞等的摄取和处理，暴露出抗原，</span></span>
<span class="line"><span>抗原被传递给T细胞，刺激T细胞产生淋巴因子。</span></span>
<span class="line"><span>少数抗原直接刺激B细胞，B细胞在淋巴因子的作用下，</span></span>
<span class="line"><span>增殖分化为浆细胞和记忆细胞，浆细胞分泌抗体，</span></span>
<span class="line"><span>抗体与抗原特异性结合，形成沉淀或细胞集团，</span></span>
<span class="line"><span>进而被吞噬细胞吞噬消化。</span></span></code></pre></div><hr><h2 id="四、配套练习" tabindex="-1">四、配套练习 <a class="header-anchor" href="#四、配套练习" aria-label="Permalink to &quot;四、配套练习&quot;">​</a></h2><h3 id="基础练习" tabindex="-1">基础练习 <a class="header-anchor" href="#基础练习" aria-label="Permalink to &quot;基础练习&quot;">​</a></h3><p><strong>练习1</strong>：兴奋在神经纤维上的传导形式是什么？在神经元之间的传递形式是什么？</p><p><strong>练习2</strong>：胰岛素和胰高血糖素在血糖调节中起什么作用？它们之间的关系是什么？</p><p><strong>练习3</strong>：生长素的生理作用有什么特点？请举例说明。</p><p><strong>参考答案</strong>：</p><ul><li>练习1：电信号；电信号→化学信号→电信号</li><li>练习2：胰岛素降低血糖，胰高血糖素升高血糖；拮抗作用</li><li>练习3：两重性，低浓度促进，高浓度抑制；如顶端优势</li></ul><hr><h2 id="五、faq常见问题" tabindex="-1">五、FAQ常见问题 <a class="header-anchor" href="#五、faq常见问题" aria-label="Permalink to &quot;五、FAQ常见问题&quot;">​</a></h2><h3 id="faq-1-突触传递为什么是单向的" tabindex="-1">FAQ 1：突触传递为什么是单向的？ <a class="header-anchor" href="#faq-1-突触传递为什么是单向的" aria-label="Permalink to &quot;FAQ 1：突触传递为什么是单向的？&quot;">​</a></h3><p><strong>答</strong>：因为神经递质只存在于突触前膜的突触小泡中，只能由突触前膜释放，作用于突触后膜。</p><h3 id="faq-2-血糖调节中胰岛素和胰高血糖素的关系" tabindex="-1">FAQ 2：血糖调节中胰岛素和胰高血糖素的关系？ <a class="header-anchor" href="#faq-2-血糖调节中胰岛素和胰高血糖素的关系" aria-label="Permalink to &quot;FAQ 2：血糖调节中胰岛素和胰高血糖素的关系？&quot;">​</a></h3><p><strong>答</strong>：拮抗作用（作用相反，共同维持血糖稳定）；还有反馈调节。</p><h3 id="faq-3-体液免疫和细胞免疫的区别" tabindex="-1">FAQ 3：体液免疫和细胞免疫的区别？ <a class="header-anchor" href="#faq-3-体液免疫和细胞免疫的区别" aria-label="Permalink to &quot;FAQ 3：体液免疫和细胞免疫的区别？&quot;">​</a></h3><p><strong>答</strong>：体液免疫主要对付细胞外的病原体，产生抗体；细胞免疫主要对付细胞内的病原体，产生效应T细胞裂解靶细胞。</p><hr><p><strong>文档编号</strong>: Bio-Learn-Detail-003<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,124)])])}const u=a(l,[["render",i]]);export{c as __pageData,u as default};
